mapper.select:
SELECT CP.SERVICE_ID, TS.CAR_NO, TS.COMPANY_ID, TC.COMPANY_NM, TO_CHAR(CP.PRINT_DT, 'YYYYMMDD') AS PRINT_DT FROM TR_CAR_PAPER CP, TR_SERVICE TS, TM_COMPANY TC WHERE CP.SERVICE_ID = TS.SERVICE_ID AND TS.COMPANY_ID = TC.COMPANY_ID
AND TS.COMPANY_ID = #{COMPANY_ID}
ORDER BY CP.PRINT_DT DESC

SELECT NL.NUM_ID, NL.CAR_NO, NL.COMPANY_ID, TC.COMPANY_NM, TO_CHAR(NL.ISSUE_DT, 'YYYYMMDD') AS ISSUE_DT, TO_CHAR(NL.RETURN_DT, 'YYYYMMDD') AS RETURN_DT FROM TM_NUMPLATE_LIST NL, TM_COMPANY TC WHERE NL.COMPANY_ID = TC.COMPANY_ID(+) AND NL.NUM_ST = 'TEMP'
AND NL.COMPANY_ID = #{COMPANY_ID}
ORDER BY NL.ISSUE_DT DESC

SELECT NS.SUPPLY_ID, NS.COMPANY_ID, TC.COMPANY_NM, NS.SUPPLY_QTY, TO_CHAR(NS.SUPPLY_DT, 'YYYYMMDD') AS SUPPLY_DT FROM TM_NUMPLATE_SUPPLY NS, TM_COMPANY TC WHERE NS.COMPANY_ID = TC.COMPANY_ID(+)
AND NS.COMPANY_ID = #{COMPANY_ID}
ORDER BY NS.SUPPLY_DT DESC
